import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom'; // Importing from react-router-dom
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // To manage login state

  // Handle login success (simulate login in this case)
  const login = () => {
    setIsAuthenticated(true);
  };

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="App">
        <h1>Jira Test Case Generator</h1>

        <Routes>
          <Route path="/Login" element={<LoginPage login={login} />} />
          <Route path="/Signup" element={<SignupPage />} />

          {/* Redirect to Login if not authenticated */}
          <Route
            path="/Main"
            element={isAuthenticated ? <MainPage logout={logout} /> : <Navigate to="/Login" />}
          />

          {/* Default route */}
          <Route path="/" element={<Navigate to="/Login" />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
